                    <th>Date</th>
                    <th>Location</th>
                    <th>Status</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Location</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

