                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTime(2026, 5, 15, 16, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 17, 7, 30, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 17, 14, 22, 0, DateTimeKind.Utc) },
            ]
        },
        ["PKG-003"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTime(2026, 6, 5, 18, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = new DateTime(2026, 5, 25, 10, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Awaiting carrier pickup", Location = "Dallas, TX", Timestamp = new DateTime(2026, 5, 25, 12, 0, 0, DateTimeKind.Utc) },
            ]
        }
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct = default)
    {
        await Task.Delay(1500, ct);

        if (!SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            throw new KeyNotFoundException($"Shipment '{trackingNumber}' not found.");
        }

        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@implements IAsyncDisposable
@inject IShipmentService ShipmentService
@inject ILogger<TrackShipment> Logger

<PageTitle>Track Shipment @TrackingNumber</PageTitle>

<h2>Shipment Tracking</h2>

@if (error is not null)
{
    <div class="alert alert-danger">
        <p>@error</p>
        <button class="btn btn-outline-danger btn-sm mt-2" @onclick="LoadAsync">Retry</button>
    </div>
}
else if (shipment is null)
{
    <div class="alert alert-info">
        <p>Loading shipment <strong>@TrackingNumber</strong>…</p>
    </div>
}
else
{
    @if (isLoading)
    {
        <p><em>Refreshing…</em></p>
    }

    <div class="card mb-3">
        <div class="card-body">
            <h5 class="card-title">@shipment.TrackingNumber</h5>
            <p><strong>Status:</strong> @shipment.Status</p>
            <p><strong>Location:</strong> @shipment.Location</p>
            @if (shipment.EstimatedDelivery.HasValue)
            {
                <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.Value.ToString("f")</p>
            }
        </div>
    </div>

    @if (shipment.StatusUpdates.Count > 0)
    {
        <h4>Tracking History</h4>
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Location</th>
                    <th>Status</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Location</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter] public string TrackingNumber { get; set; } = "";

    private CancellationTokenSource? cts;
    private string? loadedTrackingNumber;
    private ShipmentDetails? shipment;
    private bool isLoading;
    private string? error;

    protected override async Task OnParametersSetAsync()
    {
        if (string.Equals(TrackingNumber, loadedTrackingNumber, StringComparison.OrdinalIgnoreCase))
        {
            return;
        }

        loadedTrackingNumber = TrackingNumber;
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
        }

        cts = new CancellationTokenSource();
        var cancellationToken = cts.Token;

        error = null;
        isLoading = true;

        try
        {
            var result = await ShipmentService.GetShipmentAsync(TrackingNumber, cancellationToken);
            shipment = result;
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // Self-cancellation (disposal or parameter change) — let ComponentBase handle it.
            throw;
        }
        catch (OperationCanceledException ex)
        {
            Logger.LogWarning(ex, "Request timed out for shipment {TrackingNumber}", TrackingNumber);
            error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load shipment {TrackingNumber}", TrackingNumber);
            error = "Something went wrong loading this shipment. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
        }
    }
}

